const article = $input.first().json.content?.[0]?.text || '';
const topic = $('Pick Daily Topic').first().json;
const template = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${topic.topic} | LogicMinimizer Blog</title><meta name="description" content="${topic.topic} - step by step guide with examples. Free digital logic tools at logic1min.me."><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600&family=JetBrains+Mono:wght@400;700&display=swap" rel="stylesheet"><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Inter',sans-serif;background:#0a0a0f;color:#e0e0e0;line-height:1.7;padding:2rem 1rem}article{max-width:700px;margin:0 auto}h1{font-family:'JetBrains Mono',monospace;color:#00ff88;font-size:1.8rem;margin-bottom:1.5rem}p{margin-bottom:1rem;font-size:1rem}code{background:#141420;padding:.2rem .4rem;border-radius:4px;font-family:'JetBrains Mono',monospace;color:#00ff88}pre{background:#141420;padding:1rem;border-radius:8px;overflow-x:auto;margin:1rem 0;font-family:'JetBrains Mono',monospace;color:#e0e0e0}a{color:#00ff88}.back{display:inline-block;margin-bottom:1rem;color:#00ff88;text-decoration:none;font-family:'JetBrains Mono',monospace}</style></head><body><article><a href="../index.html" class="back">← LogicMinimizer</a>${article}</article></body></html>`;

return [{json: {content: template, path: topic.filename, message: 'Add blog: ' + topic.topic}}];
